import{_ as e,o as t,c as o,a0 as n}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"단간론파 3 -The End of 키보가미네 학원-","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/animations/단간론파-3--The-End-of-키보가미네-학원-.md","filePath":"outta-space/knowledge/animations/단간론파-3--The-End-of-키보가미네-학원-.md"}'),r={name:"outta-space/knowledge/animations/단간론파-3--The-End-of-키보가미네-학원-.md"};function _(d,a,h,i,l,s){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="단간론파-3-the-end-of-키보가미네-학원" tabindex="-1">단간론파 3 -The End of 키보가미네 학원- <a class="header-anchor" href="#단간론파-3-the-end-of-키보가미네-학원" aria-label="Permalink to &quot;단간론파 3 -The End of 키보가미네 학원-&quot;">​</a></h1><p>미래편, 절망편, 희망편을 모두 포함한다. 미래편 - 절망편 순서로 보고, 마지막인 희망편을 보았다.</p><h2 id="_1-이야기와-전개" tabindex="-1">1. 이야기와 전개 <a class="header-anchor" href="#_1-이야기와-전개" aria-label="Permalink to &quot;1. 이야기와 전개&quot;">​</a></h2><p>가장 메인이 되는 전개는 미래기관 인원들이 벌이는 살인 게임이다. 다만 살인 게임의 흑막이 절망의 잔당이 아닌 회장이라는 점이 신박했다. 아니 그리고 이거 추리물인데 왜 살인 게임에서 액션 배틀물을 찍고 있는 거임?</p><p>1편과 2편 게임을 재밌게 했던 사람으로서, 스토리 자체는 볼만했다고 느꼈다. 다만 77기생 세뇌까지는 이해하겠는데 (나나미 치아키 관련이니까) 예비학과 세뇌나 마지막 미라타이의 세뇌는 너무 작위적이라고 느꼈다. 기승전 세뇌도 정도껏이어야지.</p><h2 id="_2-캐릭터와-감정선" tabindex="-1">2. 캐릭터와 감정선 <a class="header-anchor" href="#_2-캐릭터와-감정선" aria-label="Permalink to &quot;2. 캐릭터와 감정선&quot;">​</a></h2><p>소모되는 캐릭터가 너무 많다. 반다이 미안해! 캐릭터를 이렇게 많이 만든 이유가 그냥 설정 보여주려고 하는거라니. 정말 아쉽다.</p><p>미라타이 료타에 대해서는 할 말이 많다. 애니메이터가 세뇌 가능한 애니메이션을 만들 수 있다는 설정이 너무 작위적이다. 그리고 결말에 대해서도 할 말이 많은데 왜 그리 죄책감을 느꼈음에도 불구하고 마지막에는 희망 세뇌 비디오를 만드려고 했는가? 그럼 차라리 나에기의 말에 감화되는 연출이라도 넣던가. 희망편 없었으면</p><h2 id="_3-작화와-영상미" tabindex="-1">3. 작화와 영상미 <a class="header-anchor" href="#_3-작화와-영상미" aria-label="Permalink to &quot;3. 작화와 영상미&quot;">​</a></h2><p>가장 인상깊었던 건 미래편과 절망편의 작화가 다르다는 점이다. 특히 절망편의 둥글둥글한 작화와 절망적인 진행이 겹쳐 기괴함이 묻어난다.</p><p>영상미... 15세인데 이렇게 잔인해도 되는거임?</p><h2 id="_4-음악과-성우-연기" tabindex="-1">4. 음악과 성우 연기 <a class="header-anchor" href="#_4-음악과-성우-연기" aria-label="Permalink to &quot;4. 음악과 성우 연기&quot;">​</a></h2><p>음악. 원작 팬이라면 심장이 두근거릴 OST가 많이 나오는 편이다. 원작 재현도 잘했고..</p><h2 id="_5-주제와-여운" tabindex="-1">5. 주제와 여운 <a class="header-anchor" href="#_5-주제와-여운" aria-label="Permalink to &quot;5. 주제와 여운&quot;">​</a></h2><p>뭘 말하고 싶은 건지 모르겠다. 엄청난 망작이라 그래서 보기 시작했는데, 한 10화까지는 그정도는 아니라 생각했다. 스토리도 짜임새 있고, 기승전 세뇌도 에노시마 준코의 계략이라 생각하면 뭐 나쁘지 않은데 난 미라타이가 맘에 안 들어.</p>',15)])])}const f=e(r,[["render",_]]);export{c as __pageData,f as default};
